mapper.select:
SELECT b.*, bc.name as category_name FROM book b LEFT JOIN book_category bc ON b.category_id = bc.id WHERE b.deleted = 0
AND MATCH(b.title, b.author) AGAINST(#{keyword} IN BOOLEAN MODE)
AND b.category_id = #{categoryId}
AND b.status = #{status}
ORDER BY b.create_time DESC

SELECT b.*, bc.name as category_name FROM book b LEFT JOIN book_category bc ON b.category_id = bc.id WHERE b.deleted = 0
AND b.title LIKE CONCAT('%', #{title}, '%')
AND b.author LIKE CONCAT('%', #{author}, '%')
AND b.isbn LIKE CONCAT('%', #{isbn}, '%')
AND b.publisher LIKE CONCAT('%', #{publisher}, '%')
AND b.category_id = #{categoryId}
AND b.publish_date >= #{publishDateStart}
AND b.publish_date <= #{publishDateEnd}
ORDER BY b.borrow_count DESC ORDER BY b.publish_date DESC ORDER BY b.create_time DESC
